// Pico Servo Sweep
// Sweeps a servo motor from 0° to 180° and back on GP15.

#include <Arduino.h>
#include <Servo.h>

const int SERVO_PIN = 15;
Servo myServo;

void setup() {
  myServo.attach(SERVO_PIN);
  Serial.begin(115200);
  delay(100);
  Serial.println("Pico Servo Sweep started");
}

void loop() {
  // Sweep from 0 to 180
  for (int angle = 0; angle <= 180; angle += 2) {
    myServo.write(angle);
    if (angle % 30 == 0) {
      Serial.print("Angle: ");
      Serial.println(angle);
    }
    delay(20);
  }

  // Sweep from 180 to 0
  for (int angle = 180; angle >= 0; angle -= 2) {
    myServo.write(angle);
    if (angle % 30 == 0) {
      Serial.print("Angle: ");
      Serial.println(angle);
    }
    delay(20);
  }
}
